import http from '../http'
//产品管理


//产品

// 专利列表
export function pathannList(query: any) {
    return http.get('/jkyErp/patent/list', query)
}

// 产品详细
export function getpathann(id: any) {
    return http.get('/jkyErp/patent/' + id)
}
// 新增产品
export function addpathann(data: any) {
    return http.post('/jkyErp/patent/add', data)
}

// 修改产品
export function editpathann(data: any) {
    return http.post('/jkyErp/patent/edit', data)
}

// 删除产品
export function delpathann(teamId: number) {
    return http.post('/jkyErp/patent/del',teamId)
}


export function sysOsssc(query: File) {
    return http.post('/jkyErp/sysOss/postAnnounce', query)
}







