<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div :class="advanced ? null : 'fold'">
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item
                label="专利名称搜索"
                :labelCol="{ span: 5 }"
                :wrapperCol="{ span: 18, offset: 1 }"
              >
                <a-input
                  placeholder="请输入专利名称"
                  v-model:value="queryParams.patentname"
                />
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 3px">
          <a-button type="primary" @click="handleSearch">查询</a-button>
          <a-button style="margin-left: 8px" @click="Reset">重置</a-button>
          <a @click="toggleAdvanced" style="margin-left: 8px">
            {{ advanced ? "收起" : "展开" }}
          </a>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary">新建</a-button>
        <a-button
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
      </a-space>
      <a-table
        rowKey="id"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>

  <a-modal
    :visible="open"
    :title="title"
    width="650px"
    @ok="handleOk"
    @cancel="handleCancel"
  >
    <a-form :model="form" :rules="rules">
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="所属产品" :rules="[{ required: true }]">
            <a-select
              :allowClear="true"
              showSearch
              optionFilterProp="lable"
              v-model:value="form.producid"
              placeholder="请选择产品"
            >
              <a-select-option
                v-for="item in selteamList"
                :key="item.productId"
                :lable="item.productName"
                :value="item.productId"
              >
                {{ item.productName }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>

        <a-col :span="12">
          <a-form-item label="专利名称" name="patentname">
            <a-input
              placeholder="请输入专利方法名称"
              v-model:value="form.patentname"
            />
          </a-form-item>
        </a-col>
      </a-row>

      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="申请人" name="patenproposer">
            <a-input placeholder="申请人" v-model:value="form.patenproposer" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="申请日期">
            <a-date-picker
              v-model:value="form.patenttime"
              type="date"
              valueFormat="yyyy-MM-DD"
              placeholder="请选择入编日期"
              style="width: 100%"
            />
          </a-form-item>
        </a-col>
      </a-row>

      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="证书图片">
            <a-upload
              v-model:file="file"
              :show-upload-list="false"
              :customRequest="customRequest"
              :before-upload="beforeUpload"
            >
              <img
                v-if="form.url"
                :src="form.url"
                alt="avatar"
                style="width: 40px; heidht: 40px"
              />
              <div v-else>
                <a-button>
                  <UploadOutlined></UploadOutlined>
                  点击上传图片
                </a-button>
              </div>
            </a-upload>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="描述">
            <a-textarea
              rows="4"
              placeholder="描述"
              v-model:value="form.patentms"
              show-count
              :maxlength="100"
            />
          </a-form-item>
        </a-col>
      </a-row>
    </a-form>
  </a-modal>
</template>

<script>
const columns = [
  {
    title: "编号",
    dataIndex: "id",
  },
  {
    title: "专利名称",
    dataIndex: "patentname",
    scopedSlots: { customRender: "patentname" },
  },
  {
    title: "专利时间",
    dataIndex: "patenttime",
    scopedSlots: { customRender: "patenttime" },
  },
  {
    title: "申请人",
    dataIndex: "patenproposer",
    scopedSlots: { customRender: "patenproposer" },
  },
  {
    title: "资料或者描述",
    dataIndex: "patentms",
    scopedSlots: { customRender: "patentms" },
  },
  {
    title: "所属产品",
    dataIndex: "producname",
    scopedSlots: { customRender: "producname" },
  },
];
const rules = {
  patentname: [{ required: true, message: "该为必填项", trigger: "blur" }],
  patenproposer: [{ required: true, message: "该为必填项", trigger: "blur" }],
};
import {
  pathannList,
  addpathann,
  getpathann,
  delpathann,
  editpathann,
} from "@/server/http/api/pathenn";
import { ProductListAll } from "@/server/http/api/Product";
import { message } from "ant-design-vue";
import { uploadFile, delFile } from "@/server/http/api/File";
import { UploadOutlined } from "@ant-design/icons-vue";
export default {
  name: "QueryList",
  components: { UploadOutlined },
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      advanced: false,
      columns: columns,
      rules: rules,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: {},
      file: null,
      Pagination: {},
      total: 0,

      queryParams: {
        current: 1,
        size: 10,
        patentname: undefined,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      selteamList: [],
      //用来存储修改的临时文件路径
      updateUrl: null,
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.getList();
  },
  mounted() {
    this.getProductTypeList();
  },
  methods: {
    delFileMethod(e) {
      delFile({ fileUrl: e }).then((res) => {});
    },
    //证书图片上传
    customRequest(info) {
      const formData = new FormData();
      formData.append("file", info.file);
      if (this.form.url != null && this.updateUrl != this.form.url) {
        this.delFileMethod(this.form.url);
      }
      uploadFile(formData).then((res) => {
        this.form.url = res.data.data.fileUrl;
      });
    },
    //证书图片传前
    beforeUpload(file) {
      const isJpgOrPng =
        file.type === "image/jpeg" || file.type === "image/png";
      if (!isJpgOrPng) {
        message.warning("只能上传图片!");
      }
      const isLt5M = file.size / 1024 / 1024 < 5;

      if (!isLt5M) {
        message.warning("图片大小不能超过5M!");
      }
      return isJpgOrPng && isLt5M;
    },
    getProductTypeList() {
      ProductListAll().then((res) => {
        var data = res.data;
        this.selteamList = data.data;
      });
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备分类列表
    getList() {
      pathannList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    //查询数据
    handleSearch() {
      this.getList();
    },

    Reset() {
      this.queryParams = {
        current: 1,
        size: 10,
        patentname: undefined,
      };
      this.getList();
    },
    handleOk(e) {
      if (
        !this.form.patentname ||
        !this.form.patenproposer ||
        !this.form.producid
      ) {
        message.warning("缺少必填参数!");
        return;
      }
      this.submitForm();
    },
    handleCancel(e) {
      if (this.form.url != null && this.updateUrl != this.form.url) {
        this.delFileMethod(this.form.url);
      }
      this.updateUrl = null;
      this.form = {};
      this.open = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      this.open = true;
      this.title = "添加专利";
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      getpathann(this.selectedRowKeys[0]).then((response) => {
        this.loading = false;
        this.form = response.data.data;
        this.open = true;
        this.title = "修改专利信息";
        this.updateUrl = response.data.data.url;
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.id != null) {
        if (this.form.url != this.updateUrl) {
          this.delFileMethod(this.updateUrl);
        }
        editpathann(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addpathann(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      delpathann(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>
